import{c as a,cG as e,cb as r,c8 as i,cf as n,cT as l,ce as o}from"./chunks/framework.BlkIsu1j.js";const h=JSON.parse('{"title":"Windows 10 系统编程","description":"","frontmatter":{"title":"Windows 10 系统编程","outline":"deep","layout":"doc","prev":false,"next":true,"sidebar":true,"date":"2026-05-30T00:00:00.000Z"},"headers":[],"relativePath":"windows/system-programming/index.md","filePath":"windows/system-programming/index.md","lastUpdated":1780122742000}'),t={id:"frontmatter-title",tabindex:"-1"};const d=a({name:"windows/system-programming/index.md"},[["render",function(a,h,d,s,p,c){return e(),r("div",null,[i("h1",t,[n(l(a.$frontmatter.title)+" ",1),h[0]||(h[0]=i("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":"Permalink to “{{ $frontmatter.title }}”"},"​",-1))]),h[1]||(h[1]=o('<h2 id="引言" tabindex="-1">引言 <a class="header-anchor" href="#引言" aria-label="Permalink to “引言”">​</a></h2><blockquote><p>本教程基于 Pavel Yosifovich 所著《Windows 10 System Programming》的内容整理编写，面向想要深入理解 Windows 10 系统级编程的开发者。</p></blockquote><p>这应该是继《Windows核心编程》之后、最近十年最好且唯一的关于 Windows 编程的书，其涉及的内容涵盖 <strong>Windows 7</strong> 到 <strong>Windows 10</strong> 程序的方方面面，非常详尽、通俗易懂。</p><p>很多人觉得利用 Windows API 进行 Windows 原生编程已经日薄西山了，Windows 系统不常用了，这其实是程序员的幸存者偏差。学习 Windows 编程的好处如下：</p><ul><li>在如今的求职大环境下，Windows 和 Linux C/C++ 双修，更有竞争力；</li><li>很多著名的开源代码都有 Windows 版本，熟悉 Windows 编程让学习这些源码变得容易；</li><li>最后一点，也是最重要的一点，就是提高你技术人生的职业容错性——如果被迫退居二三线城市，庞大的 Windows 软件需求市场，让你能够为其他人或者公司开发一些 Windows 实用工具或者软件。</li></ul><p>本专栏翻译自 Pavel Yosifovich 的《<strong>Windows 10 System Programming</strong>》，首发于 <a href="https://www.cppguide.cn/" target="_blank" rel="noreferrer">cppguide.cn</a>。</p><h3 id="适合阅读本书的人群" tabindex="-1">适合阅读本书的人群 <a class="header-anchor" href="#适合阅读本书的人群" aria-label="Permalink to “适合阅读本书的人群”">​</a></h3><p>本书面向以 Windows 平台为目标的软件开发人员，这些人员需要获得更高级别的框架和库无法实现的控制能力。</p><p>该书使用 C 和 C++ 编写示例，因为 Windows API 大多基于 C 语言。当 C++ 在维护性、清晰度、资源管理等方面更优时才会使用它。书中不会使用复杂的 C++ 结构（如模板元编程），重点不在于 C++，而在于 Windows。</p><p>其他语言可通过互操作机制调用 Windows API，例如 .NET 语言（C#、VB、F# 等）可以使用平台调用（P/Invoke）来调用 Windows API，而 Python、Rust、Java 等也都有各自等效的功能。</p><h3 id="使用本书前应了解的内容" tabindex="-1">使用本书前应了解的内容 <a class="header-anchor" href="#使用本书前应了解的内容" aria-label="Permalink to “使用本书前应了解的内容”">​</a></h3><p>读者应熟练掌握 C 编程语言，尤其要熟悉指针、结构体及其标准库，因为这些在 Windows API 中频繁出现。强烈建议读者具备基本的 C++ 知识，不过仅精通 C 语言也可以研读本书。</p><h3 id="示例代码" tabindex="-1">示例代码 <a class="header-anchor" href="#示例代码" aria-label="Permalink to “示例代码”">​</a></h3><p>本书所有示例代码可在 CppGuide 的 GitHub 仓库获取：<a href="https://github.com/balloonwj/CppGuide" target="_blank" rel="noreferrer">https://github.com/balloonwj/CppGuide</a>。</p><h2 id="目录" tabindex="-1">目录 <a class="header-anchor" href="#目录" aria-label="Permalink to “目录”">​</a></h2><h3 id="第1章-基础" tabindex="-1">第1章：基础 <a class="header-anchor" href="#第1章-基础" aria-label="Permalink to “第1章：基础”">​</a></h3><p>Windows 架构概述、进程、动态链接库、虚拟内存、线程、通用系统架构、Windows 应用程序开发、第一个应用程序、处理字符串、C/C++ 运行时中的字符串、字符串输出参数、安全字符串函数、32 位与 64 位开发、编码规范、C++ 用法、处理 API 错误、定义自定义错误代码、Windows 版本</p><h3 id="第2章-对象和句柄" tabindex="-1">第2章：对象和句柄 <a class="header-anchor" href="#第2章-对象和句柄" aria-label="Permalink to “第2章：对象和句柄”">​</a></h3><p>内核对象、运行单实例进程、句柄、伪句柄、句柄的 RAII、使用 WIL、创建对象、对象名称、共享内核对象（按名称共享、通过句柄复制共享）、私有对象命名空间、用户对象和 GDI 对象</p><h3 id="第3章-进程" tabindex="-1">第3章：进程 <a class="header-anchor" href="#第3章-进程" aria-label="Permalink to “第3章：进程”">​</a></h3><p>进程基础、Process Explorer 中的进程、进程创建、main 函数、进程环境变量、CreateProcess、句柄继承、进程驱动器目录、进程属性、受保护进程和 PPL 进程、UWP 进程、最小化进程和 Pico 进程、进程终止、枚举进程</p><h3 id="第4章-作业" tabindex="-1">第4章：作业 <a class="header-anchor" href="#第4章-作业" aria-label="Permalink to “第4章：作业”">​</a></h3><p>作业简介、创建作业、嵌套作业、查询作业信息、作业记账、设置作业限制、作业通知、隔离仓</p><h3 id="第5章-线程基础" tabindex="-1">第5章：线程基础 <a class="header-anchor" href="#第5章-线程基础" aria-label="Permalink to “第5章：线程基础”">​</a></h3><p>Socket/内核/逻辑处理器、创建和管理线程、质数计数器应用、终止线程、线程栈、线程名称、C++ 标准库对比</p><h3 id="第6章-线程调度" tabindex="-1">第6章：线程调度 <a class="header-anchor" href="#第6章-线程调度" aria-label="Permalink to “第6章：线程调度”">​</a></h3><p>优先级、调度基础、时间片、处理器组、多处理器调度、亲和力、CPU 集、后台模式、优先级提升、暂停和恢复、睡眠和让步</p><h3 id="第7章-线程同步-进程内" tabindex="-1">第7章：线程同步（进程内） <a class="header-anchor" href="#第7章-线程同步-进程内" aria-label="Permalink to “第7章：线程同步（进程内）”">​</a></h3><p>原子操作、Interlocked 函数族、临界区、死锁、读写锁、条件变量、等待地址、同步屏障</p><h3 id="第8章-线程同步-进程间" tabindex="-1">第8章：线程同步（进程间） <a class="header-anchor" href="#第8章-线程同步-进程间" aria-label="Permalink to “第8章：线程同步（进程间）”">​</a></h3><p>Mutex、Semaphore、Event、Waitable Timer、可提醒等待、GUI 线程等待</p><h3 id="第9章-线程池" tabindex="-1">第9章：线程池 <a class="header-anchor" href="#第9章-线程池" aria-label="Permalink to “第9章：线程池”">​</a></h3><p>工作回调、等待回调、定时器回调、I/O 回调、回调环境、私有线程池、清理组</p><h3 id="第10章-高级线程处理" tabindex="-1">第10章：高级线程处理 <a class="header-anchor" href="#第10章-高级线程处理" aria-label="Permalink to “第10章：高级线程处理”">​</a></h3><p>TLS、远程线程、线程枚举、缓存和缓存行、等待链遍历、UMS、Init Once、调试多线程</p><h3 id="第11章-文件和设备-i-o" tabindex="-1">第11章：文件和设备 I/O <a class="header-anchor" href="#第11章-文件和设备-i-o" aria-label="Permalink to “第11章：文件和设备 I/O”">​</a></h3><p>CreateFile、符号链接、同步/异步 I/O、I/O 完成端口、I/O 取消、管道和邮槽、事务性 NTFS、NTFS 流</p><h3 id="第12章-内存管理基础" tabindex="-1">第12章：内存管理基础 <a class="header-anchor" href="#第12章-内存管理基础" aria-label="Permalink to “第12章：内存管理基础”">​</a></h3><p>进程地址空间、页面状态、地址空间布局、内存计数器、VMMap、共享内存、页面文件、WOW64、虚拟地址转换</p><h3 id="第13章-内存操作" tabindex="-1">第13章：内存操作 <a class="header-anchor" href="#第13章-内存操作" aria-label="Permalink to “第13章：内存操作”">​</a></h3><p>VirtualAlloc、工作集、堆、C/C++ 运行时、内存保护、锁定内存、跨进程读写、大页面、NUMA</p><h3 id="第14章-内存映射文件" tabindex="-1">第14章：内存映射文件 <a class="header-anchor" href="#第14章-内存映射文件" aria-label="Permalink to “第14章：内存映射文件”">​</a></h3><p>文件映射、共享内存（文件后备）、数据一致性</p><h3 id="第15章-动态链接库" tabindex="-1">第15章：动态链接库 <a class="header-anchor" href="#第15章-动态链接库" aria-label="Permalink to “第15章：动态链接库”">​</a></h3><p>构建 DLL、隐式/显式链接、调用约定、DllMain、DLL 注入、Windows 钩子、API 挂钩、延迟加载</p><h3 id="第16章-安全性" tabindex="-1">第16章：安全性 <a class="header-anchor" href="#第16章-安全性" aria-label="Permalink to “第16章：安全性”">​</a></h3><p>SID、令牌、模拟、特权、安全描述符、UAC、完整性级别、UIPI、CFG、进程缓解</p><h3 id="第17章-注册表" tabindex="-1">第17章：注册表 <a class="header-anchor" href="#第17章-注册表" aria-label="Permalink to “第17章：注册表”">​</a></h3><p>根键、CRUD 操作、注册表通知、事务性注册表、远程注册表</p>',49))])}]]);export{h as __pageData,d as default};
